+import LooseObject from '../data/LooseObject';
+import FavoriteController from '../pages/favoritepage/favoriteController';
+
+@Reusable
+@Component
+export struct FavoriteListItem {
+  @State item: LooseObject = {};
+  @State index: number = 0;
+  @State isShowHead: boolean = true;
+  @State textDirection: string = 'ltr';
+  @State isPC: boolean = false;
+  @State isPad: boolean = false;
+  @State padMargin: number = 0;
+  @State screenWidth: number = 0;
+  @State mFavoriteCtrl: FavoriteController = FavoriteController.getInstance();
+  @State listScroller: Scroller = new Scroller();
+  @State scrollEndIndex: number = 0;
+  @State scrollStartIndex: number = 0;
+  @State favoriteContentAlignRules: AlignRuleOption = {};
+  
+  onChatbotClick: (senderNumber: string) => void = () => {};
+  onAvatarClick: (senderNumber: string) => void = () => {};
+  onMenuMultSelect: (selectIndex: number) => void = () => {};
+  onMenuDelete: (deleteItem: LooseObject) => void = () => {};
+  buildMmsContentMap: (item: LooseObject, index: number, id: string) => void = () => {};
+
+  aboutToReuse(params: Record<string, ESObject>) {
+    this.item = params.item;
+    this.index = params.index;
+    this.isShowHead = params.isShowHead;
+    this.textDirection = params.textDirection;
+    this.isPC = params.isPC;
+    this.isPad = params.isPad;
+    this.padMargin = params.padMargin;
+    this.screenWidth = params.screenWidth;
+    this.mFavoriteCtrl = params.mFavoriteCtrl;
+    this.listScroller = params.listScroller;
+    this.scrollEndIndex = params.scrollEndIndex;
+    this.scrollStartIndex = params.scrollStartIndex;
+    this.favoriteContentAlignRules = params.favoriteContentAlignRules;
+    this.onChatbotClick = params.onChatbotClick;
+    this.onAvatarClick = params.onAvatarClick;
+    this.onMenuMultSelect = params.onMenuMultSelect;
+    this.onMenuDelete = params.onMenuDelete;
+    this.buildMmsContentMap = params.buildMmsContentMap;
+  }
+
+  build() {
+    RelativeContainer() {
+      if (this.isShowHead) {
+        if (this.item.senderNumber) {
+          if (this.item?.isChatbotMessage) {
+            ContactAvatar({
+              rawContactId: '',
+              contactId: '',
+              item: this.item
+            })
+              .margin(this.textDirection === 'rtl' ?
+                {
+                  top: 16,
+                  right: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_right')
+                } :
+                {
+                  top: 16,
+                  left: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_left')
+                })
+              .id('favorite_list_avatar')
+              .onClick(() => {
+                this.onChatbotClick(this.item.senderNumber);
+              })
+          } else {
+            ContactAvatar({
+              hasYellowPageIcon: this.mFavoriteCtrl
+                .nameAndPicture(this.item.senderNumber)?.hasYellowPageIcon,
+              yellowPageId: this.mFavoriteCtrl
+                .nameAndPicture(this.item.senderNumber)?.yellowPageId,
+              rawContactId: this.mFavoriteCtrl.contactIdMap.get(this.item.senderNumber) ?? '',
+              contactId: this.mFavoriteCtrl.contactIdMap.get(this.item.senderNumber) ?? '',
+              item: this.item,
+            })
+              .onClick(() => {
+                this.onAvatarClick(this.item.senderNumber);
+              })
+              .margin(this.textDirection === 'rtl' ?
+                {
+                  top: 16,
+                  right: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_right')
+                } :
+                {
+                  top: 16,
+                  left: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_left')
+                })
+              .id('favorite_list_avatar')
+          }
+        } else {
+          ContactAvatar({
+            rawContactId: this.mFavoriteCtrl.nameNoPicture('')?.rawContactId,
+            contactId: this.mFavoriteCtrl.nameNoPicture('')?.contactId,
+            item: this.item
+          })
+            .margin(this.textDirection === 'rtl' ?
+              {
+                top: 16,
+                right: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_right')
+              } :
+              {
+                top: 16,
+                left: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_left')
+              })
+            .id('favorite_list_avatar')
+        }
+      }
+      FavoriteName({
+        hasYellowPageIcon: this.mFavoriteCtrl
+          .nameAndPicture(this.item.senderNumber)?.hasYellowPageIcon,
+        item: this.item,
+        isPad: this.isPad,
+        isShowHead: this.isShowHead,
+        textDirection: this.textDirection,
+      })
+      if (this.item.msgType === 0 || this.item.msgType === 2) {
+        bubbleText({
+          conversationCtrl: this.mFavoriteCtrl,
+          content: this.item.msgContent,
+          item: this.item,
+          itemIndex: this.index,
+          bubbleTextBackgroundColor: this.item.isSender === 0
+            ? $r('app.color.brand') : $r('sys.color.ohos_id_color_card_bg'),
+          isAdvancedSecurity: this.item.isAdvancedSecurity,
+          isSender: this.item.isSender,
+          detectResContent: this.item.detectResContent,
+          textDirection: this.textDirection,
+          listScroller: this.listScroller,
+          scrollEndIndex: this.scrollEndIndex,
+          scrollStartIndex: this.scrollStartIndex,
+          menuMultSelect: ((selectIndex) => {
+            this.onMenuMultSelect(selectIndex);
+          }),
+          menuDeleteCallBack: ((deleteItem) => {
+            this.onMenuDelete(deleteItem);
+          })
+        }).margin({ top: 4, bottom: 8 })
+          .alignRules(this.favoriteContentAlignRules)
+          .id('favorite_list_content')
+      }
+      else if (this.item.msgType === 1) {
+        if (MmsUtil.isSlideType(this.item.contentType)) {
+          FavoriteSlideComponent({
+            itemIndex: this.index,
+            item: this.item,
+            listScroller: this.listScroller,
+            scrollEndIndex: this.scrollEndIndex,
+            scrollStartIndex: this.scrollStartIndex,
+            menuMultSelect: ((selectIndex) => {
+              this.onMenuMultSelect(selectIndex);
+            }),
+            menuDeleteCallBack: ((deleteItem) => {
+              this.onMenuDelete(deleteItem);
+            })
+          }).alignRules(this.favoriteContentAlignRules)
+            .id('favorite_list_content')
+        } else if (this.mFavoriteCtrl.mmsScreening(this.item.msgId, 8)) {
+          this.buildMmsContentMap(this.item, this.index, 'favorite_list_content')
+        } else if (!this.item.msgContent &&
+          this.mFavoriteCtrl.mmsScreening(this.item.msgId, 1)) {
+          MmsContentImage({
+            imageProps: this.mFavoriteCtrl.mmsScreening(this.item.msgId, 1).locationPath ?? '',
+            ct: this.mFavoriteCtrl.mmsScreening(this.item.msgId, 1).ct ?? '',
+            screenWidth: this.screenWidth,
+            itemIndex: this.index,
+            item: this.item,
+            listScroller: this.listScroller,
+            scrollEndIndex: this.scrollEndIndex,
+            scrollStartIndex: this.scrollStartIndex,
+            menuMultSelect: ((selectIndex) => {
